<?php
$pageTitle='User Branch Access';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('org_structure');
$pdo=getDB();
$scopeOptions=scopeSelectOptions($pdo);
$users=$pdo->query('SELECT id,email,first_name,last_name,role FROM '.table('users').' WHERE role IN ("admin","employee") ORDER BY role,email')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){
  $userId=(int)($_POST['user_id']??0);$companyId=(int)($_POST['company_id']??0);$branchId=(int)($_POST['branch_id']??0);$warehouseId=(int)($_POST['warehouse_id']??0);
  if($userId<=0){flash('error','Select a user.');redirect(ADMIN_URL.'/erp/user-branch-access.php');}
  if(!empty($_POST['is_default'])){$pdo->prepare('UPDATE '.table('user_branch_access').' SET is_default=0 WHERE user_id=?')->execute([$userId]);$pdo->prepare('UPDATE '.table('users').' SET default_company_id=?,default_branch_id=?,default_warehouse_id=? WHERE id=?')->execute([$companyId?:null,$branchId?:null,$warehouseId?:null,$userId]);}
  $stmt=$pdo->prepare('INSERT INTO '.table('user_branch_access').' (user_id,company_id,branch_id,warehouse_id,can_view,can_transact,is_default) VALUES (?,?,?,?,?,?,?)');
  $stmt->execute([$userId,$companyId?:null,$branchId?:null,$warehouseId?:null,!empty($_POST['can_view'])?1:0,!empty($_POST['can_transact'])?1:0,!empty($_POST['is_default'])?1:0]);
  logActivity($pdo,'Organization','user_branch_access_added','Branch access assigned to user #'.$userId.'.','user',$userId);flash('success','User branch access created.');redirect(ADMIN_URL.'/erp/user-branch-access.php');
}
if(isset($_GET['delete'])){$pdo->prepare('DELETE FROM '.table('user_branch_access').' WHERE id=?')->execute([(int)$_GET['delete']]);flash('success','Access row removed.');redirect(ADMIN_URL.'/erp/user-branch-access.php');}
$rows=$pdo->query('SELECT uba.*,u.email,u.first_name,u.last_name,c.company_code,c.company_name,b.branch_code,b.branch_name,w.warehouse_code,w.warehouse_name FROM '.table('user_branch_access').' uba LEFT JOIN '.table('users').' u ON u.id=uba.user_id LEFT JOIN '.table('companies').' c ON c.id=uba.company_id LEFT JOIN '.table('branches').' b ON b.id=uba.branch_id LEFT JOIN '.table('warehouses').' w ON w.id=uba.warehouse_id ORDER BY u.email,uba.is_default DESC')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4"><div class="erp-kicker">User Scope</div><h2 class="h5 mb-3">Assign Access</h2><div class="mb-3"><label class="form-label">User</label><select class="form-select" name="user_id"><?php foreach($users as $user): ?><option value="<?php echo (int)$user['id']; ?>"><?php echo esc($user['email'].' · '.$user['role']); ?></option><?php endforeach; ?></select></div><div class="mb-3"><label class="form-label">Company</label><select class="form-select" name="company_id"><?php foreach($scopeOptions['companies'] as $company): ?><option value="<?php echo (int)$company['id']; ?>"><?php echo esc($company['company_code'].' · '.$company['company_name']); ?></option><?php endforeach; ?></select></div><div class="mb-3"><label class="form-label">Branch</label><select class="form-select" name="branch_id"><?php foreach($scopeOptions['branches'] as $branch): ?><option value="<?php echo (int)$branch['id']; ?>"><?php echo esc($branch['branch_code'].' · '.$branch['branch_name']); ?></option><?php endforeach; ?></select></div><div class="mb-3"><label class="form-label">Warehouse</label><select class="form-select" name="warehouse_id"><?php foreach($scopeOptions['warehouses'] as $warehouse): ?><option value="<?php echo (int)$warehouse['id']; ?>"><?php echo esc($warehouse['warehouse_code'].' · '.$warehouse['warehouse_name']); ?></option><?php endforeach; ?></select></div><div class="d-grid gap-2 mb-3"><label class="form-check form-switch"><input class="form-check-input" type="checkbox" name="can_view" value="1" checked><span class="form-check-label">Can view</span></label><label class="form-check form-switch"><input class="form-check-input" type="checkbox" name="can_transact" value="1" checked><span class="form-check-label">Can transact</span></label><label class="form-check form-switch"><input class="form-check-input" type="checkbox" name="is_default" value="1"><span class="form-check-label">Set as default</span></label></div><button class="btn btn-brand">Assign Access</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Access Matrix</h2><table class="table align-middle"><thead><tr><th>User</th><th>Company</th><th>Branch</th><th>Warehouse</th><th>Rights</th><th></th></tr></thead><tbody><?php foreach($rows as $row): ?><tr><td><strong><?php echo esc($row['email']); ?></strong></td><td><?php echo esc(($row['company_code']?$row['company_code'].' · ':'').$row['company_name']); ?></td><td><?php echo esc(($row['branch_code']?$row['branch_code'].' · ':'').$row['branch_name']); ?></td><td><?php echo esc(($row['warehouse_code']?$row['warehouse_code'].' · ':'').$row['warehouse_name']); ?></td><td><?php echo !empty($row['can_view'])?'View ':''; ?><?php echo !empty($row['can_transact'])?'Transact ':''; ?><?php if(!empty($row['is_default'])): ?><span class="badge bg-primary">Default</span><?php endif; ?></td><td class="text-end"><a class="btn btn-sm btn-outline-danger" href="?delete=<?php echo (int)$row['id']; ?>">Remove</a></td></tr><?php endforeach; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>